  border-radius: 50%;
  animation: pulse 1s infinite alternate, flicker 0.5s infinite alternate;
  box-shadow: 0 0 10px rgba(255, 0, 170, 0.7);
}

.scanlines {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: linear-gradient(
    rgba(18, 16, 36, 0) 50%,
    rgba(0, 0, 0, 0.25) 50%
  );
  background-size: 100% 4px;
  pointer-events: none;
  animation: scanline 0.5s steps(1) infinite;
}

.game-over {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  background: rgba(10, 10, 18, 0.9);
  padding: 30px;
  border: 2px solid #ff00aa;
  box-shadow: 0 0 20px rgba(255, 0, 170, 0.5);
  text-align: center;
  animation: glitch 1s infinite;
  z-index: 10;
}

.game-over h2 {
  font-family: 'Press Start 2P', cursive;
  font-size: 2rem;
  color: #ff00aa;
  margin-bottom: 10px;
}

.restart-button {
  background: #ff00aa;
  color: #fff;
  border: none;
  padding: 10px 20px;
  font-family: 'Press Start 2P', cursive;
  font-size: 0.8rem;
  margin-top: 20px;
  cursor: pointer;
  border-radius: 4px;
  box-shadow: 0 0 10px rgba(255, 0, 170, 0.5);
  transition: all 0.2s;
}

.restart-button:hover {
  background: #ff0062;
  box-shadow: 0 0 20px rgba(255, 0, 170, 0.7);
}

.pause-overlay {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  background: rgba(0, 0, 0, 0.7);
  color: #00f0ff;
  font-family: 'Press Start 2P', cursive;
  font-size: 1.5rem;
  padding: 20px;
  border: 2px solid #00f0ff;
  box-shadow: 0 0 20px rgba(0, 240, 255, 0.5);
  z-index: 10;
}

@keyframes pulse {
  0% {
    transform: scale(0.8);
    opacity: 0.8;
  }
  100% {
    transform: scale(1.2);
    opacity: 1;
  }
}

@keyframes flicker {
  0% {
    opacity: 0.8;
  }
  100% {
    opacity: 1;
  }
}

@keyframes scanline {
  0% {
    background-position: 0 0;
  }
  100% {
    background-position: 0 4px;
  }
}

@keyframes glitch {
  0% {
    transform: translate(-50%, -50%) skew(0deg);
  }
  20% {
    transform: translate(-50%, -50%) skew(2deg);
  }
  40% {
    transform: translate(-50%, -50%) skew(-1deg);
  }
  60% {
    transform: translate(-50%, -50%) skew(1deg);
  }
  80% {
    transform: translate(-50%, -50%) skew(-2deg);
  }
  100% {
    transform: translate(-50%, -50%) skew(0deg);
  }
}

:root {
  --primary: #00f0ff;
  --secondary: #ff00aa;
  --accent: #ff0062;
  --bg: #0a0a12;
  --text: #fff;
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  background: var(--bg);
  color: var(--text);
  font-family: 'Rajdhani', sans-serif;
  overflow: hidden;
}

.app-container {
  display: flex;
  justify-content: center;
  align-items: center;
  min-height: 100vh;
  padding: 20px;
}
